// ユーザー作成キャラをマージ
function getAllChars() {
  try {
    const userChars = JSON.parse(localStorage.getItem('user_chars') || '[]');
    const extra = {};
    userChars.forEach(c => { extra[c.id] = c; });
    return { ...CHARACTERS, ...extra };
  } catch(e) { return CHARACTERS; }
}

// トーク数取得
function getTalkCount(id) {
  return parseInt(localStorage.getItem('talk_count_' + id) || '0', 10);
}